__kernel void dynproc_kernel(const int iteration,
                             __global const int* gpuWall,
                             __global int* gpuSrc,
                             __global int* gpuResults,
                             const int cols,
                             const int rows,
                             const int startStep,
                             const int borderCols,
                             const int halo,
                             __local int* prev,
                             __local int* result,
                             __global int* outputBuffer)
{
    size_t gid = get_global_id(0);
    if (gid != 0)
        return;

    (void)rows;
    (void)borderCols;
    (void)halo;
    (void)prev;
    (void)result;
    (void)outputBuffer;

    for (int step = 0; step < iteration; ++step) {
        const int wall_base = (startStep + step) * cols;

        if ((step & 1) == 0) {
            for (int n = 0; n < cols; ++n) {
                int minv = gpuSrc[n];
                if (n > 0 && gpuSrc[n - 1] < minv)
                    minv = gpuSrc[n - 1];
                if (n < cols - 1 && gpuSrc[n + 1] < minv)
                    minv = gpuSrc[n + 1];
                gpuResults[n] = gpuWall[wall_base + n] + minv;
            }
        } else {
            for (int n = 0; n < cols; ++n) {
                int minv = gpuResults[n];
                if (n > 0 && gpuResults[n - 1] < minv)
                    minv = gpuResults[n - 1];
                if (n < cols - 1 && gpuResults[n + 1] < minv)
                    minv = gpuResults[n + 1];
                gpuSrc[n] = gpuWall[wall_base + n] + minv;
            }
        }
    }

    if ((iteration & 1) == 0) {
        for (int n = 0; n < cols; ++n) {
            gpuResults[n] = gpuSrc[n];
        }
    }
}
